class Solution:
    def checkDuplicates(self, head: ListNode) -> bool:
        current = head
        visited = set()
        while current:
            if current.val in visited:
                return True
            visited.add(current.val)
            current = current.next
        return False
    def main(self):
        from typing import List
        class ListNode:
            def __init__(self, val=0, next=None):
                self.val = val
                self.next = next

        n = int(input())
        head = ListNode()
        current = head
        for val in map(int, input().split()):
            current.next = ListNode(val)
            current = current.next

        print(self.checkDuplicates(head.next))

    def run(self):
        self.main()

if __name__ == '__main__':
    solution = Solution()
    solution.run()

