class Solution {
public:
    bool checkDuplicates(ListNode* head) {
        if (!head || !head->next) return false;
        ListNode* current = head->next;
        while(current) {
            if(head->val == current->val) return true;
            head = current;
            current = current->next;
        }
        return false;
    }

    void main() {
        int n,
            i;
        scanf("%d", &n);
        scanf("%d", &head);
        for(i = 0; i < n - 1; i++) scanf("%d", &head->next);

        printf(checkDuplicates(head) ? "\nTrue" : "\nFalse");
   }
};
